import{_ as t,c as e,o as a,a4 as i}from"./chunks/framework.HaEZziQ1.js";const r="/FrontEndLearnNotes/assets/Git和svn对比.CEu0jTtc.jpg",G=JSON.parse('{"title":"学习指引","description":"","frontmatter":{},"headers":[],"relativePath":"Document/Git/Guide.md","filePath":"Document/Git/Guide.md","lastUpdated":1709668918000}'),o={name:"Document/Git/Guide.md"},s=i('<h1 id="学习指引" tabindex="-1">学习指引 <a class="header-anchor" href="#学习指引" aria-label="Permalink to &quot;学习指引&quot;">​</a></h1><p>Git（读音为/gɪt/）是一个开源的分布式版本控制系统，可以有效、高速地处理从很小到非常大的项目版本管理。 也是[Linus Torvalds](<a href="https://baike.baidu.com/item/Linus" target="_blank" rel="noreferrer">https://baike.baidu.com/item/Linus</a> Torvalds/9336769?fromModule=lemma_inlink)为了帮助管理Linux内核开发而开发的一个开放源码的版本控制软件。</p><hr><p>Git官网：<a href="https://git-scm.com/about" target="_blank" rel="noreferrer">About - Git (git-scm.com)</a></p><h2 id="git与svn" tabindex="-1">Git与SVN <a class="header-anchor" href="#git与svn" aria-label="Permalink to &quot;Git与SVN&quot;">​</a></h2><p>1.SVN是集中式版本控制系统，版本库是集中放在中央服务器的，而工作的时候，用的都是自己的电脑，所以首先要从中央服务器得到最新的版本，然后工作，完成工作后，需要把自己的代码推送到中央服务器。集中式版本控制系统是必须联网才能工作</p><p>2.Git是分布式版本控制系统，没有中央服务器，每个人的电脑就是一个完整的版本库，工作的时候不需要联网了，因为版本都在自己电脑上，可以离线工作</p><p>Git与SVN对比图例：</p><p><img src="'+r+'" alt="Git和svn对比"></p><hr><h2 id="git软件安装和说明" tabindex="-1">Git软件安装和说明 <a class="header-anchor" href="#git软件安装和说明" aria-label="Permalink to &quot;Git软件安装和说明&quot;">​</a></h2>',11),n=[s];function c(d,l,_,p,h,m){return a(),e("div",null,n)}const f=t(o,[["render",c]]);export{G as __pageData,f as default};
